const b = $input.first().json.body || $input.first().json;

// Event metadata
const meta = {
  guide_opened:                  { label: '👁️ فتح الملف',             level: 'info',    color: '#3b82f6', bg: '#eff6ff', title: 'تم فتح الدليل السري' },
  login_success:                 { label: '✅ دخول ناجح',              level: 'success', color: '#16a34a', bg: '#f0fdf4', title: 'دخول ناجح للدليل' },
  login_failed:                  { label: '❌ كلمة مرور خاطئة',        level: 'danger',  color: '#dc2626', bg: '#fef2f2', title: '🚨 محاولة دخول فاشلة' },
  screenshot_attempt:            { label: '📸 محاولة تصوير الشاشة',   level: 'danger',  color: '#dc2626', bg: '#fef2f2', title: '🚨 محاولة التقاط الشاشة' },
  window_blur_suspected_capture: { label: '🎥 محاولة تسجيل الشاشة',  level: 'warning', color: '#d97706', bg: '#fffbeb', title: '⚠️ محاولة تسجيل مشتبه بها' },
  devtools_attempt:              { label: '🔧 محاولة فتح DevTools',    level: 'danger',  color: '#dc2626', bg: '#fef2f2', title: '🚨 محاولة فحص الكود' },
  right_click_attempt:           { label: '🖱️ نقر يمين',              level: 'warning', color: '#d97706', bg: '#fffbeb', title: '⚠️ محاولة نقر يمين' },
  copy_attempt:                  { label: '📋 محاولة نسخ نص',         level: 'warning', color: '#d97706', bg: '#fffbeb', title: '⚠️ محاولة نسخ المحتوى' },
  guide_closed:                  { label: '🚪 إغلاق الملف',            level: 'info',    color: '#6366f1', bg: '#eef2ff', title: 'تم إغلاق الدليل' }
};

const evt = meta[b.event_type] || { label: b.event_type, level: 'info', color: '#64748b', bg: '#f8fafc', title: b.event_type };

// Parse device from user agent
const ua = b.user_agent || '';
let device = 'غير معروف';
if (/iPhone|iPad/.test(ua)) device = 'Apple iPhone/iPad';
else if (/Android/.test(ua)) device = 'Android Mobile';
else if (/Mac/.test(ua)) device = 'Mac';
else if (/Windows/.test(ua)) device = 'Windows PC';
else if (/Linux/.test(ua)) device = 'Linux';

let browser = 'غير معروف';
if (/Chrome/.test(ua) && !/Chromium|Edge/.test(ua)) browser = 'Google Chrome';
else if (/Firefox/.test(ua)) browser = 'Mozilla Firefox';
else if (/Safari/.test(ua) && !/Chrome/.test(ua)) browser = 'Safari';
else if (/Edge/.test(ua)) browser = 'Microsoft Edge';

const mapsLink = b.maps_link || (b.lat && b.lon ? `https://www.google.com/maps?q=${b.lat},${b.lon}` : null);
const nowAr = new Date(b.timestamp || Date.now()).toLocaleString('ar-SA', { timeZone: b.timezone || 'Asia/Riyadh', dateStyle: 'full', timeStyle: 'short' });

return [{ json: {
  ...b,
  event_label: evt.label,
  event_title: evt.title,
  event_level: evt.level,
  event_color: evt.color,
  event_bg:    evt.bg,
  device, browser,
  maps_link: mapsLink,
  time_ar: nowAr
}}];
